# Build DPO preference pairs from thumbs signals on regenerated responses
from dataclasses import dataclass

@dataclass
class PreferencePair:
    prompt: str
    chosen: str    # thumbs-up response
    rejected: str  # thumbs-down or pre-regenerate response

def extract_preference_pairs(session_id: str) -> list[PreferencePair]:
    turns = get_session_turns(session_id)
    pairs = []
    for i, turn in enumerate(turns):
        if turn.signal == "regenerate" and i + 1 < len(turns):
            next_turn = turns[i + 1]
            if next_turn.signal == "thumbs_up":
                # User regenerated and liked the new response
                pairs.append(PreferencePair(
                    prompt=turn.user_message,
                    chosen=next_turn.response,
                    rejected=turn.response,
                ))
    return pairs

